#include<bits/stdc++.h>
using namespace std;
bool f(int a){
	for(int i=2;i*i<=a;i++)
		if(a%i==0) return 0;
	return 1;
}
int main(void){
	vector<int> v;
	int n,back=0,i=2;
	cin>>n;
	while(back<n){
		if(f(i)){
			v.push_back(i);
			back+=i;
		}
		i++;
	}
	if(back>n){
		v.pop_back();
	}
	for(i=0;i<v.size();i++)cout<<v[i]<<endl;
	cout<<v.size();
	return 0;
}
